const retrogamingQuestions = [
  {t:"m",q:"\u00bfCu\u00e1l es considerado uno de los primeros videojuegos electr\u00f3nicos de la historia?",o:["Pong", "Tennis for Two", "Pac-Man", "Space Invaders"],a:1,exp:"Tennis for Two fue creado en 1958 por William Higinbotham y es considerado uno de los primeros videojuegos electr\u00f3nicos.",extra:"Se jugaba en un osciloscopio y simulaba una partida de tenis vista de lado. No fue un producto comercial, sino una demostraci\u00f3n cient\u00edfica para visitantes de un laboratorio."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Atari populariz\u00f3 masivamente los videojuegos arcade en los a\u00f1os 70?",o:["Pong", "Asteroids", "Centipede", "Breakout"],a:0,exp:"Pong, lanzado por Atari en 1972, fue uno de los primeros grandes \u00e9xitos comerciales de los videojuegos.",extra:"Su sencillez fue clave: dos paletas, una pelota y puntuaci\u00f3n. Demostr\u00f3 que los videojuegos pod\u00edan ser un negocio rentable fuera de laboratorios y universidades."},
  {t:"m",q:"\u00bfQui\u00e9n fund\u00f3 Atari junto con Ted Dabney?",o:["Shigeru Miyamoto", "Nolan Bushnell", "Ralph Baer", "Gunpei Yokoi"],a:1,exp:"Nolan Bushnell fund\u00f3 Atari junto con Ted Dabney en 1972.",extra:"Atari fue una de las compa\u00f1\u00edas m\u00e1s influyentes de la primera era comercial de los videojuegos, especialmente en arcades y consolas dom\u00e9sticas."},
  {t:"m",q:"\u00bfQu\u00e9 consola dom\u00e9stica de Atari se volvi\u00f3 s\u00edmbolo de la primera gran generaci\u00f3n de consolas?",o:["Atari 2600", "ColecoVision", "Intellivision", "Magnavox Odyssey"],a:0,exp:"La Atari 2600 fue una consola clave por popularizar cartuchos intercambiables en hogares.",extra:"Aunque no fue la primera consola, s\u00ed fue una de las m\u00e1s influyentes. Su enorme cat\u00e1logo defini\u00f3 el mercado dom\u00e9stico antes del crash de 1983."},
  {t:"m",q:"\u00bfQu\u00e9 consola es considerada la primera consola dom\u00e9stica comercial?",o:["Atari 2600", "Magnavox Odyssey", "NES", "ColecoVision"],a:1,exp:"La Magnavox Odyssey, lanzada en 1972, es considerada la primera consola dom\u00e9stica comercial.",extra:"Fue dise\u00f1ada por Ralph Baer, conocido como uno de los padres de los videojuegos dom\u00e9sticos. Usaba tarjetas y l\u00e1minas pl\u00e1sticas para simular escenarios en la TV."},
  {t:"m",q:"\u00bfQu\u00e9 videojuego arcade japon\u00e9s de 1978 dispar\u00f3 la fiebre por los shooters espaciales?",o:["Galaga", "Space Invaders", "Defender", "Xevious"],a:1,exp:"Space Invaders, de Taito, fue un fen\u00f3meno arcade mundial desde 1978.",extra:"Su \u00e9xito fue tan grande que se asocia con la expansi\u00f3n masiva de salones arcade en Jap\u00f3n y Occidente. Tambi\u00e9n ayud\u00f3 a consolidar la idea de puntuaciones altas."},
  {t:"m",q:"\u00bfQu\u00e9 juego introdujo de forma ic\u00f3nica el concepto de \u201chigh score\u201d persistente con iniciales?",o:["Space Invaders", "Asteroids", "Pac-Man", "Donkey Kong"],a:1,exp:"Asteroids populariz\u00f3 el registro de puntuaciones altas con iniciales del jugador.",extra:"Esto convirti\u00f3 la competencia arcade en algo social: los jugadores no solo terminaban partidas, compet\u00edan por dejar su nombre visible en la m\u00e1quina."},
  {t:"m",q:"\u00bfQu\u00e9 personaje debut\u00f3 originalmente como Jumpman?",o:["Sonic", "Mario", "Mega Man", "Bomberman"],a:1,exp:"Mario debut\u00f3 como Jumpman en Donkey Kong de 1981.",extra:"En ese juego todav\u00eda no era fontanero de forma definitiva. Era un h\u00e9roe que deb\u00eda rescatar a Pauline de Donkey Kong subiendo estructuras."},
  {t:"m",q:"\u00bfQu\u00e9 dise\u00f1ador de Nintendo cre\u00f3 Donkey Kong y luego Mario y Zelda?",o:["Yu Suzuki", "Shigeru Miyamoto", "Hideo Kojima", "Satoru Iwata"],a:1,exp:"Shigeru Miyamoto cre\u00f3 Donkey Kong y fue figura central en sagas como Mario y Zelda.",extra:"Miyamoto cambi\u00f3 la industria al priorizar dise\u00f1o de juego, personajes memorables y mundos f\u00e1ciles de entender pero dif\u00edciles de dominar."},
  {t:"m",q:"\u00bfQu\u00e9 juego de 1980 convirti\u00f3 a Pac-Man en un fen\u00f3meno cultural?",o:["Pac-Man", "Dig Dug", "Mappy", "Bubble Bobble"],a:0,exp:"Pac-Man, creado por Namco, se volvi\u00f3 uno de los mayores iconos de los videojuegos.",extra:"A diferencia de muchos juegos de disparos de la \u00e9poca, Pac-Man apost\u00f3 por laberintos, persecuci\u00f3n y un personaje reconocible, ampliando mucho el p\u00fablico arcade."},
  {t:"m",q:"\u00bfCu\u00e1l era el nombre original japon\u00e9s de Pac-Man?",o:["Puck Man", "Dot Man", "Eat Man", "Maze Boy"],a:0,exp:"Pac-Man se llam\u00f3 originalmente Puck Man en Jap\u00f3n.",extra:"El nombre se cambi\u00f3 para el mercado estadounidense por miedo a que la P de Puck fuera vandalizada en las m\u00e1quinas arcade."},
  {t:"m",q:"\u00bfQu\u00e9 juego es famoso por una conversi\u00f3n de Atari 2600 considerada muy mala y ligada al crash de 1983?",o:["E.T. the Extra-Terrestrial", "Pitfall!", "Adventure", "Missile Command"],a:0,exp:"E.T. para Atari 2600 es famoso por su mala recepci\u00f3n y por asociarse al colapso del mercado estadounidense.",extra:"Durante a\u00f1os se habl\u00f3 de cartuchos enterrados en Nuevo M\u00e9xico. La excavaci\u00f3n de 2014 confirm\u00f3 que muchos juegos de Atari hab\u00edan sido enterrados all\u00ed."},
  {t:"m",q:"\u00bfQu\u00e9 evento se conoce como el \u201ccrash\u201d de los videojuegos de 1983?",o:["La ca\u00edda del mercado estadounidense de videojuegos", "El cierre de Nintendo", "El fin de los arcades japoneses", "La bancarrota de Sega"],a:0,exp:"El crash de 1983 fue una fuerte ca\u00edda del mercado de videojuegos en Estados Unidos.",extra:"Se debi\u00f3 a saturaci\u00f3n de consolas, exceso de juegos de baja calidad, p\u00e9rdida de confianza minorista y competencia de computadoras dom\u00e9sticas."},
  {t:"m",q:"\u00bfQu\u00e9 consola ayud\u00f3 a revitalizar el mercado estadounidense tras el crash?",o:["Nintendo Entertainment System", "Atari Jaguar", "Sega Saturn", "TurboGrafx-16"],a:0,exp:"La NES ayud\u00f3 a recuperar la confianza en las consolas dom\u00e9sticas a mediados de los a\u00f1os 80.",extra:"Nintendo la present\u00f3 como \u201cEntertainment System\u201d y us\u00f3 estrategias de control de calidad, licencias y accesorios para diferenciarse del mercado colapsado."},
  {t:"m",q:"\u00bfC\u00f3mo se llam\u00f3 la NES en Jap\u00f3n?",o:["Famicom", "Super Famicom", "Mega Drive", "PC Engine"],a:0,exp:"En Jap\u00f3n, la NES fue lanzada como Family Computer, conocida como Famicom.",extra:"La Famicom sali\u00f3 en 1983 y tuvo un dise\u00f1o muy distinto al modelo gris occidental de carga frontal."},
  {t:"m",q:"\u00bfQu\u00e9 robot accesorio ayud\u00f3 a Nintendo a vender la NES como juguete en EE.UU.?",o:["R.O.B.", "Gyromite Bot", "Game Boy Robot", "Famicom Droid"],a:0,exp:"R.O.B. fue un accesorio rob\u00f3tico usado como estrategia de marketing para la NES.",extra:"Aunque tuvo pocos juegos compatibles, ayud\u00f3 a presentar la consola como algo distinto a las consolas fallidas del crash."},
  {t:"m",q:"\u00bfQu\u00e9 juego ven\u00eda frecuentemente incluido con la NES y se volvi\u00f3 un cl\u00e1sico de plataformas?",o:["Super Mario Bros.", "Metroid", "Kid Icarus", "Excitebike"],a:0,exp:"Super Mario Bros. fue uno de los juegos m\u00e1s importantes del lanzamiento occidental de NES.",extra:"Su dise\u00f1o de niveles ense\u00f1aba al jugador de forma intuitiva y convirti\u00f3 a Mario en la mascota definitiva de Nintendo."},
  {t:"m",q:"\u00bfQu\u00e9 juego de NES introdujo a Samus Aran?",o:["Metroid", "Contra", "Mega Man", "Bionic Commando"],a:0,exp:"Metroid introdujo a Samus Aran en 1986.",extra:"El final revelando que Samus era una mujer fue una sorpresa importante para muchos jugadores, en una \u00e9poca donde los protagonistas femeninos eran poco comunes."},
  {t:"m",q:"\u00bfQu\u00e9 saga de Capcom presenta a un robot azul que obtiene armas de jefes derrotados?",o:["Mega Man", "Ghosts n Goblins", "Strider", "Final Fight"],a:0,exp:"Mega Man se caracteriza por derrotar Robot Masters y usar sus armas.",extra:"La libertad para elegir el orden de niveles y explotar debilidades entre jefes fue una de sus grandes ideas de dise\u00f1o."},
  {t:"m",q:"\u00bfQu\u00e9 saga de Konami populariz\u00f3 el l\u00e1tigo contra Dr\u00e1cula en NES?",o:["Castlevania", "Contra", "Gradius", "TwinBee"],a:0,exp:"Castlevania puso al jugador como un cazador de vampiros armado con l\u00e1tigo.",extra:"La serie mezcl\u00f3 horror g\u00f3tico, plataformas dif\u00edciles y m\u00fasica memorable, creando una identidad muy fuerte desde sus primeras entregas."},
  {t:"m",q:"\u00bfQu\u00e9 famoso c\u00f3digo de Konami daba ventajas en varios juegos?",o:["Arriba Arriba Abajo Abajo Izquierda Derecha Izquierda Derecha B A", "A B A B Start Select", "Izquierda Derecha Start B A", "Arriba Abajo Start Start A"],a:0,exp:"El C\u00f3digo Konami es \u201cArriba, Arriba, Abajo, Abajo, Izquierda, Derecha, Izquierda, Derecha, B, A\u201d.",extra:"Se volvi\u00f3 legendario gracias a juegos como Contra, donde otorgaba vidas extra y se transform\u00f3 en una referencia cultural gamer."},
  {t:"m",q:"\u00bfQu\u00e9 juego de NES es famoso por su dificultad cooperativa contra alien\u00edgenas?",o:["Contra", "DuckTales", "Balloon Fight", "Ice Climber"],a:0,exp:"Contra es un run and gun de Konami recordado por su acci\u00f3n y dificultad.",extra:"Su modo cooperativo y el uso del C\u00f3digo Konami lo convirtieron en un cl\u00e1sico de reuniones frente a la televisi\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 pistola de luz de NES se usaba para jugar Duck Hunt?",o:["Zapper", "Super Scope", "Light Phaser", "GunCon"],a:0,exp:"La NES Zapper era la pistola de luz usada en Duck Hunt.",extra:"Duck Hunt se volvi\u00f3 ic\u00f3nico tambi\u00e9n por el perro que se re\u00eda cuando el jugador fallaba."},
  {t:"m",q:"\u00bfQu\u00e9 consola port\u00e1til de Nintendo se lanz\u00f3 en 1989?",o:["Game Boy", "Game Gear", "Neo Geo Pocket", "WonderSwan"],a:0,exp:"La Game Boy fue lanzada por Nintendo en 1989.",extra:"A pesar de su pantalla monocrom\u00e1tica, venci\u00f3 a rivales t\u00e9cnicamente superiores gracias a precio, bater\u00eda, cat\u00e1logo y Tetris."},
  {t:"m",q:"\u00bfQu\u00e9 juego ven\u00eda incluido con Game Boy y fue clave para su \u00e9xito?",o:["Tetris", "Kirby\u2019s Dream Land", "Super Mario Land", "Dr. Mario"],a:0,exp:"Tetris fue incluido con Game Boy en muchos mercados y ayud\u00f3 enormemente a su \u00e9xito.",extra:"Su atractivo universal hizo que la Game Boy no pareciera solo para ni\u00f1os: adultos y jugadores casuales tambi\u00e9n quer\u00edan jugar Tetris."},
  {t:"m",q:"\u00bfQui\u00e9n dise\u00f1\u00f3 la Game Boy y la l\u00ednea Game & Watch?",o:["Gunpei Yokoi", "Hiroshi Yamauchi", "Masahiro Sakurai", "Yuji Naka"],a:0,exp:"Gunpei Yokoi fue el creador clave detr\u00e1s de Game & Watch y Game Boy.",extra:"Su filosof\u00eda de \u201cpensamiento lateral con tecnolog\u00eda marchita\u201d consist\u00eda en usar tecnolog\u00eda barata y probada de formas creativas."},
  {t:"m",q:"\u00bfQu\u00e9 empresa lanz\u00f3 la consola Genesis en Am\u00e9rica?",o:["Sega", "Nintendo", "NEC", "SNK"],a:0,exp:"Sega lanz\u00f3 la Genesis en Am\u00e9rica, conocida como Mega Drive en otros mercados.",extra:"La Genesis compiti\u00f3 duramente contra Super Nintendo y ayud\u00f3 a definir la guerra de consolas de los 90."},
  {t:"m",q:"\u00bfC\u00f3mo se llam\u00f3 la Sega Genesis fuera de Norteam\u00e9rica?",o:["Mega Drive", "Master System II", "Saturn", "SG-1000"],a:0,exp:"Fuera de Norteam\u00e9rica, la Genesis se llam\u00f3 Mega Drive.",extra:"El cambio de nombre se debi\u00f3 a problemas de marca registrada en Estados Unidos."},
  {t:"m",q:"\u00bfQu\u00e9 personaje fue creado por Sega para competir con Mario?",o:["Sonic the Hedgehog", "Alex Kidd", "Ristar", "ToeJam"],a:0,exp:"Sonic fue creado como mascota de Sega y rival directo de Mario.",extra:"Su velocidad, actitud y est\u00e9tica noventera ayudaron a diferenciar a Sega como una alternativa m\u00e1s \u201ccool\u201d frente a Nintendo."},
  {t:"m",q:"\u00bfEn qu\u00e9 consola debut\u00f3 Sonic the Hedgehog?",o:["Sega Genesis/Mega Drive", "Master System", "Sega Saturn", "Dreamcast"],a:0,exp:"Sonic debut\u00f3 en Sonic the Hedgehog para Genesis/Mega Drive en 1991.",extra:"Su primer nivel, Green Hill Zone, es uno de los escenarios m\u00e1s reconocibles de los videojuegos."},
  {t:"m",q:"\u00bfQu\u00e9 consola de Nintendo sucedi\u00f3 a la NES?",o:["Super Nintendo", "Nintendo 64", "GameCube", "Virtual Boy"],a:0,exp:"La Super Nintendo, o SNES, sucedi\u00f3 a la NES en la generaci\u00f3n de 16 bits.",extra:"Fue hogar de cl\u00e1sicos como Super Mario World, The Legend of Zelda: A Link to the Past, Super Metroid y Donkey Kong Country."},
  {t:"m",q:"\u00bfC\u00f3mo se llam\u00f3 la Super Nintendo en Jap\u00f3n?",o:["Super Famicom", "Famicom Disk", "Super NES 64", "Nintendo Mark III"],a:0,exp:"En Jap\u00f3n, la Super Nintendo se llam\u00f3 Super Famicom.",extra:"Su dise\u00f1o era distinto al modelo estadounidense, m\u00e1s parecido al que tambi\u00e9n lleg\u00f3 a Europa."},
  {t:"m",q:"\u00bfQu\u00e9 juego de SNES debut\u00f3 junto a la consola en muchos mercados y present\u00f3 a Yoshi?",o:["Super Mario World", "Super Mario Bros. 3", "Yoshi\u2019s Island", "Mario Paint"],a:0,exp:"Super Mario World present\u00f3 a Yoshi y fue uno de los grandes juegos iniciales de SNES.",extra:"El mapa del mundo, las salidas secretas y el dise\u00f1o de niveles lo convirtieron en uno de los plataformas m\u00e1s influyentes."},
  {t:"m",q:"\u00bfQu\u00e9 juego de SNES es considerado una obra maestra del g\u00e9nero metroidvania?",o:["Super Metroid", "F-Zero", "Pilotwings", "ActRaiser"],a:0,exp:"Super Metroid refin\u00f3 exploraci\u00f3n, atm\u00f3sfera y progresi\u00f3n basada en habilidades.",extra:"Su dise\u00f1o ambiental contaba historia con m\u00ednimos textos, usando m\u00fasica, arquitectura y ritmo de exploraci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 saga de Rare us\u00f3 gr\u00e1ficos prerenderizados para impresionar en SNES?",o:["Donkey Kong Country", "Battletoads", "Killer Instinct", "Banjo-Kazooie"],a:0,exp:"Donkey Kong Country us\u00f3 gr\u00e1ficos prerenderizados que parec\u00edan muy avanzados para SNES.",extra:"Rare cre\u00f3 modelos en estaciones Silicon Graphics y luego los adapt\u00f3 como sprites, dando al juego un aspecto distintivo."},
  {t:"m",q:"\u00bfQu\u00e9 consola de NEC compiti\u00f3 en la era de 16 bits con fuerte \u00e9xito en Jap\u00f3n?",o:["PC Engine/TurboGrafx-16", "Neo Geo", "3DO", "Jaguar"],a:0,exp:"La PC Engine, conocida como TurboGrafx-16 en Am\u00e9rica, fue muy popular en Jap\u00f3n.",extra:"Destac\u00f3 por su tama\u00f1o compacto, juegos arcade y uso temprano de formato CD-ROM mediante accesorio."},
  {t:"m",q:"\u00bfQu\u00e9 consola de SNK era famosa por llevar experiencia arcade cara al hogar?",o:["Neo Geo AES", "GameCube", "Saturn", "ColecoVision"],a:0,exp:"La Neo Geo AES ofrec\u00eda juegos casi id\u00e9nticos a los arcade de SNK.",extra:"Era extremadamente cara, tanto la consola como los cartuchos, pero se volvi\u00f3 objeto de culto por su calidad arcade."},
  {t:"m",q:"\u00bfQu\u00e9 saga de lucha de SNK naci\u00f3 en arcades Neo Geo?",o:["The King of Fighters", "Tekken", "Virtua Fighter", "Mortal Kombat"],a:0,exp:"The King of Fighters es una de las sagas de lucha m\u00e1s importantes de SNK.",extra:"Reun\u00eda personajes de varias franquicias de SNK y populariz\u00f3 combates por equipos de tres personajes."},
  {t:"m",q:"\u00bfQu\u00e9 juego de peleas de Capcom revolucion\u00f3 los arcades en 1991?",o:["Street Fighter II", "Final Fight", "Darkstalkers", "Captain Commando"],a:0,exp:"Street Fighter II convirti\u00f3 los juegos de pelea uno contra uno en fen\u00f3meno global.",extra:"Sus personajes diferenciados, combos emergentes y competencia entre jugadores definieron el g\u00e9nero durante d\u00e9cadas."},
  {t:"m",q:"\u00bfQu\u00e9 personaje de Street Fighter lanza el Hadouken?",o:["Ryu", "Chun-Li", "Guile", "Zangief"],a:0,exp:"Ryu es uno de los personajes principales de Street Fighter y usa el Hadouken.",extra:"Ryu representa el arquetipo del luchador errante dedicado a perfeccionar su t\u00e9cnica."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Midway se volvi\u00f3 pol\u00e9mico por su violencia digitalizada?",o:["Mortal Kombat", "NBA Jam", "Rampage", "Gauntlet"],a:0,exp:"Mortal Kombat gener\u00f3 controversia por su violencia, sangre y fatalities.",extra:"La pol\u00e9mica contribuy\u00f3 a la creaci\u00f3n del sistema ESRB de clasificaci\u00f3n por edades en Estados Unidos."},
  {t:"m",q:"\u00bfQu\u00e9 organizaci\u00f3n de clasificaci\u00f3n por edades surgi\u00f3 en EE.UU. tras controversias de videojuegos violentos?",o:["ESRB", "PEGI", "CERO", "BBFC"],a:0,exp:"La ESRB se cre\u00f3 en 1994 para clasificar videojuegos por edad y contenido.",extra:"Mortal Kombat y Night Trap fueron dos nombres muy mencionados en debates pol\u00edticos sobre violencia y contenido en videojuegos."},
  {t:"m",q:"\u00bfQu\u00e9 juego FMV fue pol\u00e9mico en audiencias del Senado estadounidense en los 90?",o:["Night Trap", "Myst", "Dragon\u2019s Lair", "Phantasmagoria"],a:0,exp:"Night Trap fue criticado en audiencias sobre contenido inapropiado en videojuegos.",extra:"Aunque hoy parece relativamente inocente, en su \u00e9poca fue usado como ejemplo de preocupaci\u00f3n moral por los juegos interactivos."},
  {t:"m",q:"\u00bfQu\u00e9 juego de laserdisc de 1983 destac\u00f3 por animaci\u00f3n estilo dibujo animado?",o:["Dragon\u2019s Lair", "Space Ace", "Myst", "Mad Dog McCree"],a:0,exp:"Dragon\u2019s Lair us\u00f3 animaci\u00f3n de Don Bluth y tecnolog\u00eda laserdisc.",extra:"Era visualmente espectacular para su \u00e9poca, aunque su jugabilidad depend\u00eda mucho de memorizar comandos en el momento correcto."},
  {t:"m",q:"\u00bfQu\u00e9 aventura gr\u00e1fica de LucasArts tiene como protagonista a Guybrush Threepwood?",o:["Monkey Island", "Day of the Tentacle", "Full Throttle", "Sam & Max"],a:0,exp:"Guybrush Threepwood es el protagonista de Monkey Island.",extra:"La saga destac\u00f3 por humor absurdo, di\u00e1logos brillantes y puzzles sin muertes injustas, una filosof\u00eda importante de dise\u00f1o de LucasArts."},
  {t:"m",q:"\u00bfQu\u00e9 sistema de interfaz usaron varias aventuras cl\u00e1sicas de LucasArts?",o:["SCUMM", "id Tech", "Build", "Unreal"],a:0,exp:"SCUMM fue el motor e interfaz usado en muchas aventuras gr\u00e1ficas de LucasArts.",extra:"Su nombre viene de Script Creation Utility for Maniac Mansion, porque naci\u00f3 para Maniac Mansion."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Sierra populariz\u00f3 aventuras gr\u00e1ficas con comandos escritos?",o:["King\u2019s Quest", "Doom", "Myst", "SimCity"],a:0,exp:"King\u2019s Quest fue una de las aventuras m\u00e1s importantes de Sierra On-Line.",extra:"A diferencia de LucasArts, Sierra era famosa por permitir muertes repentinas y situaciones donde el jugador pod\u00eda quedar bloqueado."},
  {t:"m",q:"\u00bfQu\u00e9 juego de 1993 de id Software populariz\u00f3 el shooter en primera persona moderno?",o:["Doom", "Wolfenstein 3D", "Quake", "Heretic"],a:0,exp:"Doom populariz\u00f3 enormemente el FPS con acci\u00f3n r\u00e1pida, mods y juego en red.",extra:"Aunque Wolfenstein 3D fue anterior, Doom tuvo un impacto cultural y t\u00e9cnico enorme, incluyendo distribuci\u00f3n shareware y comunidades de mapas."},
  {t:"m",q:"\u00bfQu\u00e9 juego de id Software antecedi\u00f3 a Doom como FPS clave?",o:["Wolfenstein 3D", "Quake II", "Hexen", "Rise of the Triad"],a:0,exp:"Wolfenstein 3D fue uno de los grandes precursores del FPS moderno.",extra:"Su velocidad, perspectiva y estructura de niveles sentaron bases que Doom ampliar\u00eda poco despu\u00e9s."},
  {t:"m",q:"\u00bfQu\u00e9 modelo de distribuci\u00f3n permiti\u00f3 jugar gratis una parte de Doom?",o:["Shareware", "Free-to-play", "Gacha", "Suscripci\u00f3n"],a:0,exp:"Doom us\u00f3 shareware: una parte del juego se distribu\u00eda gratis para promover la compra completa.",extra:"Este modelo fue muy importante en PC durante los 90, especialmente para estudios como id Software y Apogee."},
  {t:"m",q:"\u00bfQu\u00e9 juego de 1996 de id Software llev\u00f3 los FPS a entornos 3D completos?",o:["Quake", "Duke Nukem 3D", "Doom II", "Blood"],a:0,exp:"Quake fue clave por sus mundos y enemigos en 3D real, adem\u00e1s de su multijugador online.",extra:"Tambi\u00e9n impuls\u00f3 la escena competitiva de PC, servidores, clanes y speedrunning temprano."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Apogee/3D Realms hizo famoso a un h\u00e9roe musculoso y sarc\u00e1stico?",o:["Duke Nukem 3D", "Commander Keen", "Shadow Warrior", "Rise of the Triad"],a:0,exp:"Duke Nukem 3D convirti\u00f3 a Duke en un icono noventero del FPS.",extra:"Su tono irreverente, escenarios interactivos y frases tomadas de la cultura pop lo diferenciaron de Doom."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Maxis permiti\u00f3 construir y gestionar una ciudad?",o:["SimCity", "Populous", "Civilization", "Theme Park"],a:0,exp:"SimCity, dise\u00f1ado por Will Wright, populariz\u00f3 la simulaci\u00f3n de ciudades.",extra:"No ten\u00eda un objetivo final tradicional: el placer estaba en experimentar con sistemas urbanos, econom\u00eda, tr\u00e1fico y desastres."},
  {t:"m",q:"\u00bfQui\u00e9n dise\u00f1\u00f3 SimCity y m\u00e1s tarde The Sims?",o:["Will Wright", "Sid Meier", "Peter Molyneux", "John Carmack"],a:0,exp:"Will Wright fue el dise\u00f1ador de SimCity y The Sims.",extra:"Su enfoque se centr\u00f3 en crear \u201cjuguetes de software\u201d donde el jugador experimenta con sistemas m\u00e1s que seguir una historia lineal."},
  {t:"m",q:"\u00bfQu\u00e9 dise\u00f1ador est\u00e1 asociado a Civilization?",o:["Sid Meier", "Will Wright", "Richard Garriott", "Chris Sawyer"],a:0,exp:"Sid Meier es el nombre m\u00e1s asociado a Civilization.",extra:"Civilization convirti\u00f3 la historia humana en un sistema estrat\u00e9gico por turnos: explorar, expandirse, investigar y competir cultural o militarmente."},
  {t:"m",q:"\u00bfQu\u00e9 RPG occidental temprano fue creado por Richard Garriott?",o:["Ultima", "Wizardry", "Might and Magic", "Baldur\u2019s Gate"],a:0,exp:"Richard Garriott cre\u00f3 la saga Ultima.",extra:"Ultima fue muy influyente por sus mundos abiertos, \u00e9tica, conversaci\u00f3n con NPCs y ambici\u00f3n narrativa en computadoras personales."},
  {t:"m",q:"\u00bfQu\u00e9 juego japon\u00e9s de 1986 inici\u00f3 una de las sagas JRPG m\u00e1s famosas?",o:["Dragon Quest", "Final Fantasy VII", "Chrono Trigger", "EarthBound"],a:0,exp:"Dragon Quest inici\u00f3 en 1986 y ayud\u00f3 a definir el JRPG de consola.",extra:"Su arte de Akira Toriyama, combates por turnos y estructura accesible lo volvieron un fen\u00f3meno especialmente enorme en Jap\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 saga de Square naci\u00f3 con un nombre que suger\u00eda una \u201cfantas\u00eda final\u201d?",o:["Final Fantasy", "Mana", "SaGa", "Chrono"],a:0,exp:"Final Fantasy comenz\u00f3 en 1987 y se volvi\u00f3 una de las franquicias RPG m\u00e1s importantes.",extra:"Aunque su nombre tiene mucho mito alrededor, la serie termin\u00f3 siendo cualquier cosa menos final: cada entrega principal suele presentar mundo y personajes nuevos."},
  {t:"m",q:"\u00bfQu\u00e9 RPG de SNES reuni\u00f3 talentos de Dragon Quest y Final Fantasy?",o:["Chrono Trigger", "Secret of Mana", "EarthBound", "Lufia II"],a:0,exp:"Chrono Trigger reuni\u00f3 a figuras como Hironobu Sakaguchi, Yuji Horii y Akira Toriyama.",extra:"Es recordado por viajes en el tiempo, m\u00faltiples finales, ausencia de encuentros aleatorios tradicionales y ritmo narrativo excelente."},
  {t:"m",q:"\u00bfQu\u00e9 juego de SNES protagonizado por Ness se llam\u00f3 Mother 2 en Jap\u00f3n?",o:["EarthBound", "Secret of Evermore", "Illusion of Gaia", "Terranigma"],a:0,exp:"EarthBound es el nombre occidental de Mother 2.",extra:"Su ambientaci\u00f3n moderna, humor extra\u00f1o y tono emocional lo convirtieron en juego de culto, especialmente a\u00f1os despu\u00e9s de su lanzamiento."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Nintendo 64 llev\u00f3 a Mario al 3D con mundo abierto por estrellas?",o:["Super Mario 64", "Mario Kart 64", "Yoshi\u2019s Story", "Banjo-Kazooie"],a:0,exp:"Super Mario 64 redefini\u00f3 el plataformas 3D en 1996.",extra:"Su c\u00e1mara, control anal\u00f3gico y estructura de objetivos influyeron enormemente en el dise\u00f1o de juegos tridimensionales."},
  {t:"m",q:"\u00bfQu\u00e9 mando populariz\u00f3 el stick anal\u00f3gico moderno en consolas de sobremesa?",o:["Mando de Nintendo 64", "Mando de NES", "Mando de Atari 2600", "Mando de Master System"],a:0,exp:"El mando de Nintendo 64 populariz\u00f3 el stick anal\u00f3gico para juegos 3D.",extra:"Aunque no fue el primer control anal\u00f3gico de la historia, s\u00ed fue clave para hacer com\u00fan ese tipo de control en consolas modernas."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Nintendo 64 es considerado una revoluci\u00f3n para los shooters en consola?",o:["GoldenEye 007", "Perfect Dark", "Turok 2", "Doom 64"],a:0,exp:"GoldenEye 007 demostr\u00f3 que los FPS pod\u00edan funcionar muy bien en consola.",extra:"Su multijugador local a pantalla dividida se volvi\u00f3 legendario en reuniones, incluso sin estar originalmente planeado como el centro del juego."},
  {t:"m",q:"\u00bfQu\u00e9 estudio desarroll\u00f3 GoldenEye 007 para Nintendo 64?",o:["Rare", "id Software", "Nintendo EAD", "Factor 5"],a:0,exp:"Rare desarroll\u00f3 GoldenEye 007.",extra:"Rare vivi\u00f3 una etapa dorada con Nintendo, creando juegos como Donkey Kong Country, Banjo-Kazooie, Perfect Dark y Conker\u2019s Bad Fur Day."},
  {t:"m",q:"\u00bfQu\u00e9 consola de Sony naci\u00f3 tras una colaboraci\u00f3n fallida con Nintendo?",o:["PlayStation", "Dreamcast", "Saturn", "3DO"],a:0,exp:"La PlayStation surgi\u00f3 tras una fallida colaboraci\u00f3n entre Sony y Nintendo para un accesorio de CD.",extra:"La ruptura termin\u00f3 cambiando la industria: Sony entr\u00f3 al mercado de consolas y se convirti\u00f3 en uno de sus actores principales."},
  {t:"m",q:"\u00bfQu\u00e9 formato ayud\u00f3 a PlayStation a ofrecer juegos m\u00e1s grandes y cinem\u00e1ticas?",o:["CD-ROM", "Cartucho magn\u00e9tico", "MiniDVD", "Blu-ray"],a:0,exp:"PlayStation us\u00f3 CD-ROM, lo que permiti\u00f3 m\u00e1s almacenamiento que muchos cartuchos tradicionales.",extra:"El CD favoreci\u00f3 m\u00fasica grabada, video, voces y juegos con mayor volumen de contenido, aunque tambi\u00e9n introdujo tiempos de carga."},
  {t:"m",q:"\u00bfQu\u00e9 RPG de PlayStation populariz\u00f3 masivamente los JRPG en Occidente?",o:["Final Fantasy VII", "Suikoden", "Wild Arms", "Legend of Dragoon"],a:0,exp:"Final Fantasy VII fue clave para popularizar los JRPG en mercados occidentales.",extra:"Sus cinem\u00e1ticas, personajes, m\u00fasica y marketing lo convirtieron en un evento cultural de la era PlayStation."},
  {t:"m",q:"\u00bfQu\u00e9 personaje de Final Fantasy VII empu\u00f1a una enorme Buster Sword?",o:["Cloud Strife", "Squall Leonhart", "Cecil Harvey", "Terra Branford"],a:0,exp:"Cloud Strife es el protagonista de Final Fantasy VII y usa la Buster Sword.",extra:"La imagen de Cloud con esa espada se volvi\u00f3 uno de los iconos m\u00e1s reconocibles de los RPG japoneses."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Konami populariz\u00f3 el sigilo cinematogr\u00e1fico en PlayStation?",o:["Metal Gear Solid", "Silent Hill", "Contra: Legacy of War", "Suikoden II"],a:0,exp:"Metal Gear Solid llev\u00f3 el sigilo y la narrativa cinematogr\u00e1fica a gran popularidad en 1998.",extra:"Hideo Kojima us\u00f3 voces, escenas dirigidas y trucos metanarrativos, como la famosa batalla contra Psycho Mantis."},
  {t:"m",q:"\u00bfQu\u00e9 juego de terror de Capcom de 1996 acu\u00f1\u00f3 el t\u00e9rmino survival horror en su presentaci\u00f3n?",o:["Resident Evil", "Silent Hill", "Alone in the Dark", "Clock Tower"],a:0,exp:"Resident Evil se present\u00f3 como survival horror y populariz\u00f3 el g\u00e9nero en consolas.",extra:"Con c\u00e1maras fijas, recursos limitados y mansi\u00f3n laber\u00edntica, convirti\u00f3 la tensi\u00f3n en sistema de juego."},
  {t:"m",q:"\u00bfQu\u00e9 juego anterior es considerado gran precursor del survival horror 3D?",o:["Alone in the Dark", "Doom", "Myst", "Ecstatica"],a:0,exp:"Alone in the Dark, de 1992, fue un precursor fundamental del survival horror.",extra:"Us\u00f3 personajes poligonales sobre fondos fijos y una mansi\u00f3n llena de amenazas, estructura que luego Resident Evil populariz\u00f3 masivamente."},
  {t:"m",q:"\u00bfQu\u00e9 saga de Konami llev\u00f3 el terror psicol\u00f3gico a PlayStation en 1999?",o:["Silent Hill", "Castlevania", "Contra", "Gradius"],a:0,exp:"Silent Hill apost\u00f3 por terror psicol\u00f3gico, niebla y dise\u00f1o sonoro perturbador.",extra:"A diferencia de Resident Evil, su miedo no depend\u00eda solo de monstruos y escasez, sino de simbolismo, culpa y atm\u00f3sfera opresiva."},
  {t:"m",q:"\u00bfQu\u00e9 consola de Sega fue lanzada antes que PlayStation 2 y es recordada como adelantada a su tiempo?",o:["Dreamcast", "Saturn", "Mega-CD", "32X"],a:0,exp:"Dreamcast fue lanzada por Sega en 1998/1999 y es recordada con cari\u00f1o pese a su corta vida.",extra:"Inclu\u00eda m\u00f3dem en varios modelos, impuls\u00f3 juego online en consola y tuvo cl\u00e1sicos como Shenmue, Jet Set Radio y Soulcalibur."},
  {t:"m",q:"\u00bfQu\u00e9 ambicioso juego de Dreamcast fue dirigido por Yu Suzuki y simulaba vida diaria con gran detalle?",o:["Shenmue", "Crazy Taxi", "Skies of Arcadia", "Virtua Tennis"],a:0,exp:"Shenmue fue un proyecto muy ambicioso de Yu Suzuki para Dreamcast.",extra:"Combinaba exploraci\u00f3n, horarios de NPCs, combates, minijuegos y una recreaci\u00f3n detallada de Jap\u00f3n de los a\u00f1os 80."},
  {t:"m",q:"\u00bfQu\u00e9 juego arcade de Sega populariz\u00f3 carreras fren\u00e9ticas llevando pasajeros?",o:["Crazy Taxi", "Daytona USA", "OutRun", "Sega Rally"],a:0,exp:"Crazy Taxi consist\u00eda en llevar pasajeros r\u00e1pidamente por la ciudad con conducci\u00f3n extrema.",extra:"Su m\u00fasica, ritmo arcade y sentido de caos urbano lo volvieron uno de los juegos m\u00e1s recordados de Sega."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Yu Suzuki para arcades de Sega fue pionero en carreras con sensaci\u00f3n de velocidad esc\u00e9nica?",o:["OutRun", "Virtua Racing", "Hang-On", "Daytona USA"],a:0,exp:"OutRun fue un arcade de conducci\u00f3n muy influyente por su estilo, m\u00fasica y rutas ramificadas.",extra:"M\u00e1s que una simulaci\u00f3n estricta, vend\u00eda fantas\u00eda: Ferrari, carretera, sol, playa y libertad."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Sega fue uno de los primeros grandes juegos de lucha 3D?",o:["Virtua Fighter", "Tekken 3", "Soul Edge", "Fighting Vipers"],a:0,exp:"Virtua Fighter fue pionero en peleas 3D con pol\u00edgonos.",extra:"Su enfoque t\u00e9cnico y relativamente sobrio influy\u00f3 en toda una generaci\u00f3n de juegos de lucha tridimensionales."},
  {t:"m",q:"\u00bfQu\u00e9 consola de Sega tuvo dificultades frente a PlayStation y Nintendo 64?",o:["Saturn", "Master System", "Dreamcast", "Game Gear"],a:0,exp:"Sega Saturn tuvo un desempe\u00f1o complicado fuera de Jap\u00f3n.",extra:"Su arquitectura era dif\u00edcil de programar y su lanzamiento occidental sorpresa da\u00f1\u00f3 relaciones con tiendas y desarrolladores."},
  {t:"m",q:"\u00bfQu\u00e9 accesorio de Sega Genesis promet\u00eda 32 bits pero tuvo vida corta?",o:["32X", "Sega CD", "Game Genie", "Power Base Converter"],a:0,exp:"El Sega 32X fue un accesorio para Genesis/Mega Drive con vida comercial muy corta.",extra:"Sali\u00f3 cerca de la llegada de Saturn, generando confusi\u00f3n y fragmentaci\u00f3n en el p\u00fablico de Sega."},
  {t:"m",q:"\u00bfQu\u00e9 accesorio de Sega Genesis permit\u00eda juegos en CD?",o:["Sega CD/Mega-CD", "32X", "Satellaview", "Famicom Disk System"],a:0,exp:"Sega CD, o Mega-CD, a\u00f1ad\u00eda lector de CD a Genesis/Mega Drive.",extra:"Tuvo juegos interesantes, pero tambi\u00e9n muchos t\u00edtulos FMV de calidad irregular, algo t\u00edpico de la fiebre multimedia de los 90."},
  {t:"m",q:"\u00bfQu\u00e9 accesorio japon\u00e9s de SNES transmit\u00eda juegos por sat\u00e9lite?",o:["Satellaview", "Super Game Boy", "64DD", "Famicom Modem"],a:0,exp:"Satellaview fue un accesorio japon\u00e9s de Super Famicom para recibir contenido v\u00eda sat\u00e9lite.",extra:"Tuvo versiones especiales de juegos de Zelda y transmisiones con horarios, una idea muy adelantada para su \u00e9poca."},
  {t:"m",q:"\u00bfQu\u00e9 accesorio de Nintendo 64 usaba discos magn\u00e9ticos y sali\u00f3 solo en Jap\u00f3n?",o:["64DD", "Satellaview", "Famicom Disk System", "Expansion Pak"],a:0,exp:"El 64DD fue un perif\u00e9rico de discos para Nintendo 64 lanzado solo en Jap\u00f3n.",extra:"Tuvo pocos juegos y lleg\u00f3 tarde, pero est\u00e1 ligado a prototipos e ideas que terminaron influyendo en otros proyectos de Nintendo."},
  {t:"m",q:"\u00bfQu\u00e9 expansi\u00f3n de memoria era necesaria para algunos juegos de Nintendo 64?",o:["Expansion Pak", "Rumble Pak", "Transfer Pak", "Memory Pak"],a:0,exp:"El Expansion Pak a\u00f1ad\u00eda memoria RAM a Nintendo 64.",extra:"Era obligatorio para juegos como Donkey Kong 64 y permit\u00eda mejoras en t\u00edtulos como The Legend of Zelda: Majora\u2019s Mask."},
  {t:"m",q:"\u00bfQu\u00e9 accesorio de Nintendo 64 introdujo vibraci\u00f3n en el mando de forma popular?",o:["Rumble Pak", "Expansion Pak", "Transfer Pak", "Controller Pak"],a:0,exp:"El Rumble Pak a\u00f1adi\u00f3 vibraci\u00f3n al mando de Nintendo 64.",extra:"Se populariz\u00f3 con Star Fox 64 y ayud\u00f3 a convertir la retroalimentaci\u00f3n h\u00e1ptica en est\u00e1ndar de la industria."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Nintendo 64 se incluy\u00f3 con el Rumble Pak en muchos mercados?",o:["Star Fox 64", "Mario Kart 64", "GoldenEye 007", "F-Zero X"],a:0,exp:"Star Fox 64 fue el gran juego asociado al debut del Rumble Pak.",extra:"La vibraci\u00f3n reforzaba impactos y explosiones, haciendo que la acci\u00f3n espacial se sintiera m\u00e1s f\u00edsica."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Nintendo 64 populariz\u00f3 las carreras de karts en 3D con multijugador local?",o:["Mario Kart 64", "Diddy Kong Racing", "F-Zero X", "Wave Race 64"],a:0,exp:"Mario Kart 64 llev\u00f3 la f\u00f3rmula de carreras con objetos a circuitos 3D y multijugador local muy popular.",extra:"Aunque Super Mario Kart cre\u00f3 la base, Mario Kart 64 fue para muchos la experiencia definitiva de sof\u00e1 y pantalla dividida."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Rare mezcl\u00f3 carreras de karts, aventura y mundo central?",o:["Diddy Kong Racing", "Mario Kart 64", "Crash Team Racing", "Beetle Adventure Racing"],a:0,exp:"Diddy Kong Racing combin\u00f3 carreras con estructura de aventura y jefes.",extra:"Tambi\u00e9n present\u00f3 personajes que luego ser\u00edan importantes para Rare, como Banjo y Conker."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Naughty Dog fue una mascota clave de PlayStation?",o:["Crash Bandicoot", "Spyro the Dragon", "Ape Escape", "Jak and Daxter"],a:0,exp:"Crash Bandicoot fue una de las mascotas m\u00e1s reconocibles de la primera PlayStation.",extra:"Aunque Sony no lo pose\u00eda originalmente como mascota oficial, su marketing lo posicion\u00f3 como rival de Mario y Sonic."},
  {t:"m",q:"\u00bfQu\u00e9 drag\u00f3n morado de Insomniac protagoniz\u00f3 una saga de plataformas en PlayStation?",o:["Spyro", "Gex", "Croc", "Bubsy"],a:0,exp:"Spyro the Dragon fue desarrollado por Insomniac Games para PlayStation.",extra:"Sus mundos coloridos, planeo y recolecci\u00f3n de gemas lo convirtieron en uno de los plataformas 3D m\u00e1s queridos de la consola."},
  {t:"m",q:"\u00bfQu\u00e9 juego de PlayStation fue famoso por requerir DualShock por sus sticks anal\u00f3gicos?",o:["Ape Escape", "Tekken 2", "Ridge Racer", "Tomb Raider"],a:0,exp:"Ape Escape fue uno de los primeros juegos que exig\u00eda el uso del DualShock.",extra:"Su dise\u00f1o aprovechaba ambos sticks anal\u00f3gicos para mover al personaje y usar gadgets, mostrando el futuro del control 3D."},
  {t:"m",q:"\u00bfQu\u00e9 aventurera debut\u00f3 en Tomb Raider en 1996?",o:["Lara Croft", "Jill Valentine", "Claire Redfield", "Joanna Dark"],a:0,exp:"Lara Croft debut\u00f3 en Tomb Raider y se convirti\u00f3 en icono de los 90.",extra:"Su mezcla de exploraci\u00f3n, puzzles, acci\u00f3n y marketing la volvi\u00f3 una de las figuras m\u00e1s reconocibles de la era PlayStation."},
  {t:"m",q:"\u00bfQu\u00e9 juego de PC de 1993 populariz\u00f3 el CD-ROM como formato dom\u00e9stico para aventuras?",o:["Myst", "Doom", "Warcraft", "Command & Conquer"],a:0,exp:"Myst fue uno de los grandes \u00e9xitos tempranos en CD-ROM.",extra:"Sus gr\u00e1ficos prerenderizados, puzzles ambientales y tono contemplativo atrajeron a muchos jugadores fuera del p\u00fablico tradicional."},
  {t:"m",q:"\u00bfQu\u00e9 juego de estrategia de Westwood enfrentaba GDI y Nod?",o:["Command & Conquer", "Warcraft II", "Dune II", "StarCraft"],a:0,exp:"Command & Conquer presentaba la guerra entre GDI y la Hermandad de Nod.",extra:"Sus cinem\u00e1ticas FMV, interfaz r\u00e1pida y multijugador ayudaron a definir el RTS de los 90."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Westwood suele citarse como base fundamental del RTS moderno?",o:["Dune II", "Red Alert", "Warcraft III", "Age of Empires"],a:0,exp:"Dune II estableci\u00f3 muchas bases del RTS moderno.",extra:"Recolecci\u00f3n de recursos, construcci\u00f3n de bases, producci\u00f3n de unidades y facciones diferenciadas ya estaban presentes de forma reconocible."},
  {t:"m",q:"\u00bfQu\u00e9 saga de Blizzard enfrent\u00f3 originalmente orcos y humanos?",o:["Warcraft", "StarCraft", "Diablo", "Lost Vikings"],a:0,exp:"Warcraft comenz\u00f3 con el conflicto entre orcos y humanos.",extra:"Antes de convertirse en un universo enorme con WoW, Warcraft era una saga RTS muy influida por fantas\u00eda cl\u00e1sica y guerra de facciones."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Blizzard de 1998 se volvi\u00f3 legendario en esports, especialmente en Corea?",o:["StarCraft", "Diablo", "Warcraft II", "The Lost Vikings"],a:0,exp:"StarCraft se convirti\u00f3 en un pilar de los esports, especialmente en Corea del Sur.",extra:"Su equilibrio asim\u00e9trico entre terran, zerg y protoss lo hizo extremadamente profundo y competitivo."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Blizzard de 1996 populariz\u00f3 el action RPG oscuro con loot?",o:["Diablo", "Warcraft", "Blackthorne", "Rock n Roll Racing"],a:0,exp:"Diablo populariz\u00f3 el action RPG centrado en mazmorras, loot y atm\u00f3sfera oscura.",extra:"Su clic constante, generaci\u00f3n aleatoria y b\u00fasqueda de equipo marcaron una f\u00f3rmula muy influyente."},
  {t:"m",q:"\u00bfQu\u00e9 juego de carreras de Blizzard en SNES ten\u00eda banda sonora rockera?",o:["Rock n Roll Racing", "F-Zero", "Top Gear", "Uniracers"],a:0,exp:"Rock n Roll Racing fue un juego de carreras isom\u00e9tricas con m\u00fasica rock licenciada en estilo chip.",extra:"Antes de ser conocida por Warcraft, StarCraft y Diablo, Blizzard trabaj\u00f3 en juegos de consola muy variados."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Blizzard protagonizado por vikingos ten\u00eda puzzles cooperativos?",o:["The Lost Vikings", "Blackthorne", "Warcraft", "RPM Racing"],a:0,exp:"The Lost Vikings era un juego de puzzles y plataformas con tres personajes de habilidades distintas.",extra:"Cada vikingo ten\u00eda una funci\u00f3n espec\u00edfica, obligando al jugador a coordinar fuerza, defensa y movilidad."},
  {t:"m",q:"\u00bfQu\u00e9 juego arcade de 1986 de Taito protagonizaba dinosaurios que lanzaban burbujas?",o:["Bubble Bobble", "Rainbow Islands", "Puzzle Bobble", "Snow Bros."],a:0,exp:"Bubble Bobble presentaba a Bub y Bob atrapando enemigos en burbujas.",extra:"Su cooperativo, m\u00fasica pegadiza y m\u00faltiples secretos lo convirtieron en uno de los arcades m\u00e1s queridos."},
  {t:"m",q:"\u00bfQu\u00e9 puzzle arcade derivado de Bubble Bobble usa burbujas de colores?",o:["Puzzle Bobble/Bust-A-Move", "Columns", "Puyo Puyo", "Dr. Mario"],a:0,exp:"Puzzle Bobble, conocido como Bust-A-Move, usa disparos de burbujas para combinar colores.",extra:"Es uno de los grandes puzzles competitivos de arcade, f\u00e1cil de entender y muy adictivo."},
  {t:"m",q:"\u00bfQu\u00e9 juego de puzzle de Sega compiti\u00f3 con Tetris usando joyas que caen?",o:["Columns", "Puyo Puyo", "Klax", "Panel de Pon"],a:0,exp:"Columns fue el puzzle de bloques de Sega asociado especialmente a Mega Drive y Game Gear.",extra:"Usaba columnas de tres joyas y combinaciones por color, con una est\u00e9tica m\u00e1s elegante y mitol\u00f3gica."},
  {t:"m",q:"\u00bfQu\u00e9 saga de puzzle japonesa usa criaturas gelatinosas de colores?",o:["Puyo Puyo", "Columns", "Tetris Attack", "Lumines"],a:0,exp:"Puyo Puyo se basa en conectar grupos de criaturas de colores para crear cadenas.",extra:"Su profundidad competitiva viene de preparar combos encadenados que env\u00edan basura al rival."},
  {t:"m",q:"\u00bfQu\u00e9 juego de arcade de 1981 ten\u00eda a una rana cruzando calles y r\u00edos?",o:["Frogger", "Q*bert", "Dig Dug", "BurgerTime"],a:0,exp:"Frogger desaf\u00eda al jugador a cruzar tr\u00e1fico y r\u00edos evitando obst\u00e1culos.",extra:"Su premisa simple y tensi\u00f3n inmediata lo volvieron un cl\u00e1sico arcade f\u00e1cil de reconocer."},
  {t:"m",q:"\u00bfQu\u00e9 juego arcade de 1982 tiene a un personaje saltando por una pir\u00e1mide de cubos?",o:["Q*bert", "Dig Dug", "Joust", "Popeye"],a:0,exp:"Q*bert consiste en cambiar colores de cubos saltando sobre una pir\u00e1mide isom\u00e9trica.",extra:"Su lenguaje incomprensible y dise\u00f1o visual raro lo hicieron muy distintivo dentro de los arcades tempranos."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Namco permite inflar enemigos bajo tierra?",o:["Dig Dug", "Mappy", "Pac-Land", "Xevious"],a:0,exp:"Dig Dug permite derrotar enemigos infl\u00e1ndolos o soltando rocas.",extra:"Su mezcla de excavaci\u00f3n, estrategia y acci\u00f3n lo volvi\u00f3 uno de los arcades m\u00e1s creativos de Namco."},
  {t:"m",q:"\u00bfQu\u00e9 arcade de Williams ten\u00eda combates montado en avestruces voladoras?",o:["Joust", "Defender", "Robotron: 2084", "Sinistar"],a:0,exp:"Joust pon\u00eda a jugadores sobre aves voladoras compitiendo contra enemigos.",extra:"Su f\u00edsica de aleteo y colisiones le dio un estilo \u00fanico, especialmente en cooperativo."},
  {t:"m",q:"\u00bfQu\u00e9 arcade de Eugene Jarvis era un shooter fren\u00e9tico con dos joysticks?",o:["Robotron: 2084", "Defender", "Smash TV", "Tempest"],a:0,exp:"Robotron: 2084 populariz\u00f3 el control twin-stick en arcades.",extra:"Un joystick mov\u00eda al personaje y otro disparaba, permitiendo acci\u00f3n ca\u00f3tica de 360 grados."},
  {t:"m",q:"\u00bfQu\u00e9 arcade vectorial de Atari simulaba una batalla de tanques futuristas?",o:["Battlezone", "Tempest", "Gravitar", "Major Havoc"],a:0,exp:"Battlezone usaba gr\u00e1ficos vectoriales para simular combate en primera persona con tanques.",extra:"Fue tan avanzado para su \u00e9poca que incluso tuvo inter\u00e9s militar para entrenamiento simulado."},
  {t:"m",q:"\u00bfQu\u00e9 arcade vectorial de Atari fue dise\u00f1ado por Dave Theurer y tiene tubos geom\u00e9tricos?",o:["Tempest", "Asteroids", "Centipede", "Missile Command"],a:0,exp:"Tempest es un shooter vectorial famoso por sus t\u00faneles y velocidad.",extra:"Su estilo abstracto y colores intensos lo hicieron uno de los arcades m\u00e1s visualmente memorables."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Atari trata de defender ciudades de misiles entrantes?",o:["Missile Command", "Centipede", "Gravitar", "Warlords"],a:0,exp:"Missile Command obliga al jugador a interceptar misiles antes de que destruyan ciudades.",extra:"Su tensi\u00f3n refleja miedos de la Guerra Fr\u00eda, convirtiendo una mec\u00e1nica simple en una experiencia sorprendentemente angustiante."},
  {t:"m",q:"\u00bfQu\u00e9 arcade de Atari fue co-dise\u00f1ado por Ed Logg y Dona Bailey?",o:["Centipede", "Asteroids", "Pong", "Gauntlet"],a:0,exp:"Centipede fue co-dise\u00f1ado por Ed Logg y Dona Bailey.",extra:"Dona Bailey fue una de las pocas mujeres desarrolladoras visibles en la industria arcade temprana, lo que hace su aporte especialmente recordado."},
  {t:"m",q:"\u00bfQu\u00e9 arcade de Atari de fantas\u00eda permit\u00eda jugar con guerrero, mago, valquiria y elfo?",o:["Gauntlet", "Golden Axe", "Ghosts n Goblins", "Altered Beast"],a:0,exp:"Gauntlet ofrec\u00eda acci\u00f3n cooperativa con cuatro clases de fantas\u00eda.",extra:"Sus frases de voz como \u201cWizard needs food badly\u201d se volvieron parte de la memoria arcade."},
  {t:"m",q:"\u00bfQu\u00e9 beat em up de Sega ten\u00eda b\u00e1rbaros, amazonas y magia en un mundo fant\u00e1stico?",o:["Golden Axe", "Final Fight", "Double Dragon", "Streets of Rage"],a:0,exp:"Golden Axe mezcl\u00f3 fantas\u00eda heroica con combate beat em up.",extra:"Sus monturas, magia y est\u00e9tica de espada y brujer\u00eda lo hicieron muy reconocible en arcades y Mega Drive."},
  {t:"m",q:"\u00bfQu\u00e9 beat em up de Technos populariz\u00f3 peleas callejeras cooperativas en 1987?",o:["Double Dragon", "Final Fight", "River City Ransom", "Bad Dudes"],a:0,exp:"Double Dragon fue clave en la popularizaci\u00f3n del beat em up cooperativo.",extra:"Su historia de rescate, pandillas callejeras y combate lateral influy\u00f3 en muchos juegos posteriores."},
  {t:"m",q:"\u00bfQu\u00e9 beat em up de Capcom transcurre en Metro City?",o:["Final Fight", "Captain Commando", "Cadillacs and Dinosaurs", "The Punisher"],a:0,exp:"Final Fight ocurre en Metro City y enfrenta al jugador contra la banda Mad Gear.",extra:"Originalmente estuvo vinculado al desarrollo de una secuela de Street Fighter, pero termin\u00f3 definiendo el beat em up arcade de Capcom."},
  {t:"m",q:"\u00bfQu\u00e9 beat em up de Sega en Genesis ten\u00eda m\u00fasica famosa de Yuzo Koshiro?",o:["Streets of Rage", "Golden Axe", "Altered Beast", "Comix Zone"],a:0,exp:"Streets of Rage es recordado por su m\u00fasica electr\u00f3nica compuesta por Yuzo Koshiro.",extra:"Su banda sonora ayud\u00f3 a darle identidad urbana y nocturna, especialmente en Streets of Rage 2."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Capcom ten\u00eda al caballero Arthur perdiendo su armadura al recibir da\u00f1o?",o:["Ghosts n Goblins", "Ghouls n Ghosts", "Magic Sword", "Black Tiger"],a:0,exp:"Ghosts n Goblins mostraba a Arthur quedando en ropa interior tras recibir un golpe.",extra:"Tambi\u00e9n es famoso por su dificultad extrema y por exigir completar el juego dos veces para ver el final verdadero."},
  {t:"m",q:"\u00bfQu\u00e9 juego arcade de Sega iniciaba con la frase \u201cRise from your grave\u201d?",o:["Altered Beast", "Golden Axe", "Shinobi", "Shadow Dancer"],a:0,exp:"Altered Beast es recordado por la frase \u201cRise from your grave\u201d.",extra:"Fue uno de los primeros juegos destacados de Genesis/Mega Drive en Occidente y mostraba transformaciones en criaturas poderosas."},
  {t:"m",q:"\u00bfQu\u00e9 ninja de Sega protagoniz\u00f3 una saga de acci\u00f3n iniciada en arcades?",o:["Shinobi", "Ryu Hayabusa", "Strider Hiryu", "Joe Musashi"],a:3,exp:"Joe Musashi es el protagonista de Shinobi.",extra:"La saga Shinobi mezcl\u00f3 acci\u00f3n ninja, rescate de rehenes, shurikens y jefes extravagantes."},
  {t:"m",q:"\u00bfQu\u00e9 ninja de Tecmo protagoniza Ninja Gaiden?",o:["Ryu Hayabusa", "Joe Musashi", "Hanzo Hattori", "Strider Hiryu"],a:0,exp:"Ryu Hayabusa protagoniza Ninja Gaiden.",extra:"La versi\u00f3n de NES es famosa por su dificultad y por usar escenas cinem\u00e1ticas que daban peso narrativo poco com\u00fan en la \u00e9poca."},
  {t:"m",q:"\u00bfQu\u00e9 h\u00e9roe futurista de Capcom usa una espada de plasma en Strider?",o:["Strider Hiryu", "Mega Man X", "Captain Commando", "Viewtiful Joe"],a:0,exp:"Strider Hiryu es el protagonista de Strider.",extra:"El arcade fue muy admirado por su movimiento \u00e1gil, ambientaci\u00f3n futurista y sensaci\u00f3n de anime de acci\u00f3n."},
  {t:"m",q:"\u00bfQu\u00e9 juego de carreras futuristas de SNES debut\u00f3 junto a la consola?",o:["F-Zero", "Wipeout", "Top Gear", "Rock n Roll Racing"],a:0,exp:"F-Zero fue uno de los t\u00edtulos tempranos de SNES y mostr\u00f3 el Modo 7.",extra:"Su sensaci\u00f3n de velocidad y pistas futuristas ayudaron a demostrar las capacidades t\u00e9cnicas de la consola."},
  {t:"m",q:"\u00bfQu\u00e9 t\u00e9cnica gr\u00e1fica de SNES permit\u00eda rotar y escalar fondos?",o:["Modo 7", "Blast Processing", "Super FX", "Parallax CD"],a:0,exp:"El Modo 7 permit\u00eda rotar y escalar fondos para crear efectos de perspectiva.",extra:"Juegos como F-Zero, Pilotwings y Super Mario Kart usaron esta t\u00e9cnica de forma muy visible."},
  {t:"m",q:"\u00bfQu\u00e9 chip especial permiti\u00f3 gr\u00e1ficos poligonales en Star Fox de SNES?",o:["Super FX", "SA-1", "DSP-1", "S-DD1"],a:0,exp:"El chip Super FX permiti\u00f3 que Star Fox mostrara gr\u00e1ficos poligonales en SNES.",extra:"Fue una soluci\u00f3n de hardware dentro del cartucho para ampliar capacidades de la consola."},
  {t:"m",q:"\u00bfQu\u00e9 zorro piloto protagoniza Star Fox?",o:["Fox McCloud", "Falco Lombardi", "Wolf O Donnell", "Peppy Hare"],a:0,exp:"Fox McCloud es el l\u00edder del equipo Star Fox.",extra:"La saga combina shooter sobre rieles, combate espacial y personajes animales antropom\u00f3rficos."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Nintendo introdujo carreras con objetos usando personajes de Mario?",o:["Super Mario Kart", "F-Zero", "Excitebike", "Stunt Race FX"],a:0,exp:"Super Mario Kart inici\u00f3 la saga Mario Kart en SNES.",extra:"Combin\u00f3 Modo 7, personajes conocidos y objetos ca\u00f3ticos, creando una f\u00f3rmula multijugador duradera."},
  {t:"m",q:"\u00bfQu\u00e9 consola port\u00e1til de Sega compiti\u00f3 con Game Boy con pantalla a color?",o:["Game Gear", "Nomad", "Lynx", "Neo Geo Pocket"],a:0,exp:"Game Gear ofrec\u00eda pantalla a color frente a la Game Boy monocrom\u00e1tica.",extra:"Su gran problema fue el consumo de pilas, mucho mayor que el de Game Boy."},
  {t:"m",q:"\u00bfQu\u00e9 port\u00e1til de Atari fue t\u00e9cnicamente avanzada pero no venci\u00f3 a Game Boy?",o:["Atari Lynx", "Game Gear", "WonderSwan", "TurboExpress"],a:0,exp:"Atari Lynx ten\u00eda pantalla a color y hardware potente para su \u00e9poca.",extra:"Fue perjudicada por precio, tama\u00f1o, bater\u00eda y falta de cat\u00e1logo tan fuerte como el de Nintendo."},
  {t:"m",q:"\u00bfQu\u00e9 consola port\u00e1til japonesa fue dise\u00f1ada por Gunpei Yokoi tras salir de Nintendo?",o:["WonderSwan", "Neo Geo Pocket", "Game.com", "Watara Supervision"],a:0,exp:"WonderSwan fue dise\u00f1ada por Gunpei Yokoi y lanzada por Bandai.",extra:"Tuvo \u00e9xito moderado en Jap\u00f3n y versiones posteriores a color, pero nunca alcanz\u00f3 a Game Boy."},
  {t:"m",q:"\u00bfQu\u00e9 consola de Nintendo usaba gr\u00e1ficos rojos estereosc\u00f3picos y fue un fracaso comercial?",o:["Virtual Boy", "GameCube", "64DD", "Power Glove"],a:0,exp:"Virtual Boy fue una consola de Nintendo con visor de gr\u00e1ficos rojos y negros.",extra:"Su incomodidad, precio y cat\u00e1logo limitado la convirtieron en uno de los fracasos m\u00e1s famosos de Nintendo."},
  {t:"m",q:"\u00bfQu\u00e9 accesorio de NES se volvi\u00f3 famoso por su aparici\u00f3n en la pel\u00edcula The Wizard?",o:["Power Glove", "Zapper", "R.O.B.", "U-Force"],a:0,exp:"El Power Glove se volvi\u00f3 un icono pop pese a su pobre funcionamiento real.",extra:"Su promesa de control por movimiento era futurista, pero la precisi\u00f3n y soporte de juegos eran muy limitados."},
  {t:"m",q:"\u00bfQu\u00e9 pel\u00edcula de 1989 funcion\u00f3 como gran promoci\u00f3n de Super Mario Bros. 3?",o:["The Wizard", "Tron", "WarGames", "The Last Starfighter"],a:0,exp:"The Wizard mostr\u00f3 Super Mario Bros. 3 antes de su lanzamiento occidental amplio.",extra:"La escena final convirti\u00f3 al juego en un objeto de deseo para millones de ni\u00f1os."},
  {t:"m",q:"\u00bfQu\u00e9 juego de NES ten\u00eda una cortina teatral y muchos poderes de Mario?",o:["Super Mario Bros. 3", "Super Mario Bros. 2", "Kid Icarus", "Kirby\u2019s Adventure"],a:0,exp:"Super Mario Bros. 3 usa una presentaci\u00f3n teatral y ampl\u00eda enormemente los poderes de Mario.",extra:"Trajes como el de mapache, rana y Tanooki ayudaron a convertirlo en uno de los juegos m\u00e1s queridos de NES."},
  {t:"m",q:"\u00bfQu\u00e9 juego occidental de Mario se bas\u00f3 en Doki Doki Panic?",o:["Super Mario Bros. 2", "Super Mario Bros. 3", "Super Mario Land", "Mario Bros."],a:0,exp:"La versi\u00f3n occidental de Super Mario Bros. 2 fue adaptada desde Doki Doki Panic.",extra:"Por eso tiene mec\u00e1nicas distintas, como levantar enemigos y elegir entre Mario, Luigi, Peach y Toad con habilidades diferentes."},
  {t:"m",q:"\u00bfQu\u00e9 personaje rosado de Nintendo debut\u00f3 en Game Boy?",o:["Kirby", "Jigglypuff", "Birdo", "Lolo"],a:0,exp:"Kirby debut\u00f3 en Kirby\u2019s Dream Land para Game Boy.",extra:"Originalmente su dise\u00f1o simple serv\u00eda como marcador provisional, pero termin\u00f3 convirti\u00e9ndose en su aspecto definitivo."},
  {t:"m",q:"\u00bfQui\u00e9n cre\u00f3 Kirby y Super Smash Bros.?",o:["Masahiro Sakurai", "Shigeru Miyamoto", "Gunpei Yokoi", "Eiji Aonuma"],a:0,exp:"Masahiro Sakurai cre\u00f3 Kirby y m\u00e1s tarde Super Smash Bros.",extra:"Sakurai dise\u00f1\u00f3 Kirby siendo muy joven y busc\u00f3 un juego accesible para jugadores principiantes."},
  {t:"m",q:"\u00bfQu\u00e9 arcade de Nintendo protagonizado por Popeye lleg\u00f3 despu\u00e9s de Donkey Kong?",o:["Popeye", "Mario Bros.", "Balloon Fight", "Wrecking Crew"],a:0,exp:"Nintendo lanz\u00f3 Popeye como arcade en 1982.",extra:"Curiosamente, Nintendo hab\u00eda querido usar personajes de Popeye para un proyecto anterior, pero al no tener la licencia, termin\u00f3 creando Donkey Kong."},
  {t:"m",q:"\u00bfQu\u00e9 juego arcade present\u00f3 por primera vez a Mario y Luigi como fontaneros en tuber\u00edas?",o:["Mario Bros.", "Donkey Kong", "Wrecking Crew", "Super Mario Bros."],a:0,exp:"Mario Bros. de 1983 estableci\u00f3 a Mario y Luigi como fontaneros enfrentando criaturas en alcantarillas.",extra:"Antes de Super Mario Bros., este arcade ya fij\u00f3 muchos elementos b\u00e1sicos de identidad de los hermanos."},
  {t:"m",q:"\u00bfQu\u00e9 arcade de Nintendo present\u00f3 a Link?",o:["Ninguno, Link debut\u00f3 en consola", "Donkey Kong Jr.", "Mario Bros.", "Popeye"],a:0,exp:"Link no debut\u00f3 en arcade, sino en The Legend of Zelda para Famicom Disk System/NES.",extra:"Zelda naci\u00f3 como experiencia dom\u00e9stica de exploraci\u00f3n y secretos, no como juego arcade de partidas cortas."},
  {t:"m",q:"\u00bfQu\u00e9 perif\u00e9rico japon\u00e9s de Famicom usaba disquetes?",o:["Famicom Disk System", "Satellaview", "64DD", "Super Game Boy"],a:0,exp:"El Famicom Disk System permit\u00eda jugar t\u00edtulos en discos regrabables.",extra:"The Legend of Zelda apareci\u00f3 inicialmente en este formato en Jap\u00f3n, aprovechando la posibilidad de guardar progreso."},
  {t:"m",q:"\u00bfQu\u00e9 bater\u00eda en cartucho ayud\u00f3 a guardar partida en The Legend of Zelda para NES?",o:["Bater\u00eda interna", "Memory Card", "EEPROM externa", "Password manual"],a:0,exp:"The Legend of Zelda us\u00f3 bater\u00eda interna para guardar partidas en cartucho.",extra:"Fue una innovaci\u00f3n importante para juegos largos de consola, evitando depender solo de contrase\u00f1as."},
  {t:"m",q:"\u00bfQu\u00e9 juego usaba contrase\u00f1as largu\u00edsimas para continuar partidas en NES?",o:["Metroid", "Super Mario Bros.", "Duck Hunt", "Excitebike"],a:0,exp:"Metroid usaba sistema de passwords para retomar progreso.",extra:"Las contrase\u00f1as pod\u00edan guardar estado del jugador, aunque eran largas y propensas a errores al copiarlas."},
  {t:"m",q:"\u00bfQu\u00e9 famoso password de Metroid permit\u00eda jugar con Samus sin traje?",o:["JUSTIN BAILEY", "KONAMI CODE", "NARPAS SWORD", "ZELDA SECRET"],a:0,exp:"JUSTIN BAILEY es uno de los passwords m\u00e1s famosos de Metroid.",extra:"Se volvi\u00f3 leyenda de patio de escuela y revistas, aunque durante a\u00f1os hubo mitos sobre si era intencional o casual."},
  {t:"m",q:"\u00bfQu\u00e9 revista estadounidense fue clave para trucos, gu\u00edas y cultura Nintendo?",o:["Nintendo Power", "GamePro", "EGM", "Famitsu"],a:0,exp:"Nintendo Power fue una revista oficial muy influyente para fans de Nintendo.",extra:"En una \u00e9poca sin internet masivo, revistas como Nintendo Power eran esenciales para mapas, secretos, rankings y hype."},
  {t:"m",q:"\u00bfQu\u00e9 revista japonesa es famosa por sus rese\u00f1as de videojuegos?",o:["Famitsu", "Nintendo Power", "Edge", "Mean Machines"],a:0,exp:"Famitsu es una de las revistas japonesas de videojuegos m\u00e1s conocidas.",extra:"Sus puntuaciones, especialmente las notas perfectas, han sido muy comentadas hist\u00f3ricamente por jugadores y medios."},
  {t:"m",q:"\u00bfQu\u00e9 sistema permit\u00eda modificar juegos en consolas como NES y Genesis mediante c\u00f3digos?",o:["Game Genie", "Rumble Pak", "Action Pad", "Memory Pak"],a:0,exp:"Game Genie permit\u00eda introducir c\u00f3digos para alterar juegos.",extra:"Fue muy popular para conseguir vidas infinitas, saltar niveles o modificar comportamientos, aunque gener\u00f3 tensiones legales con Nintendo."},
  {t:"m",q:"\u00bfQu\u00e9 compa\u00f1\u00eda cre\u00f3 el Game Genie?",o:["Codemasters", "Nintendo", "Sega", "Atari"],a:0,exp:"Game Genie fue desarrollado por Codemasters y distribuido por Galoob.",extra:"Nintendo demand\u00f3 a Galoob en Estados Unidos, pero perdi\u00f3 el caso, permitiendo que el dispositivo siguiera vendi\u00e9ndose."},
  {t:"m",q:"\u00bfQu\u00e9 consola de 3DO tuvo apoyo de varias empresas pero precio muy alto?",o:["3DO Interactive Multiplayer", "Atari Jaguar", "CD-i", "Pippin"],a:0,exp:"La 3DO fue una plataforma licenciada a varios fabricantes, pero su precio fue demasiado alto.",extra:"Aunque tuvo tecnolog\u00eda interesante, compiti\u00f3 mal contra consolas m\u00e1s baratas y con cat\u00e1logos m\u00e1s fuertes."},
  {t:"m",q:"\u00bfQu\u00e9 consola de Atari se promocion\u00f3 como de 64 bits?",o:["Atari Jaguar", "Atari Lynx", "Atari 7800", "Atari ST"],a:0,exp:"Atari Jaguar fue promocionada como consola de 64 bits.",extra:"Su arquitectura era complicada y su cat\u00e1logo limitado. Es recordada tanto por rarezas como por su marketing agresivo."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Atari Jaguar es considerado uno de sus mejores t\u00edtulos?",o:["Tempest 2000", "Bubsy 3D", "Cybermorph", "Kasumi Ninja"],a:0,exp:"Tempest 2000 es uno de los juegos m\u00e1s respetados de Atari Jaguar.",extra:"Actualizaba el arcade Tempest con m\u00fasica electr\u00f3nica, efectos intensos y jugabilidad adictiva."},
  {t:"m",q:"\u00bfQu\u00e9 consola de Philips recibi\u00f3 infames juegos licenciados de Zelda y Mario?",o:["CD-i", "3DO", "Jaguar", "Pippin"],a:0,exp:"Philips CD-i tuvo juegos licenciados de Nintendo tras acuerdos fallidos de CD-ROM.",extra:"Los Zelda de CD-i son famosos por sus animaciones extra\u00f1as y calidad cuestionada, convirti\u00e9ndose en memes a\u00f1os despu\u00e9s."},
  {t:"m",q:"\u00bfQu\u00e9 arcade de Namco de 1993 populariz\u00f3 carreras 3D accesibles?",o:["Ridge Racer", "Daytona USA", "Virtua Racing", "Pole Position"],a:0,exp:"Ridge Racer fue un arcade de carreras 3D muy influyente de Namco.",extra:"Su versi\u00f3n para PlayStation ayud\u00f3 a mostrar las capacidades de la nueva consola de Sony."},
  {t:"m",q:"\u00bfQu\u00e9 arcade de Sega usaba la frase \u201cRolling start!\u201d?",o:["Daytona USA", "OutRun", "Sega Rally", "Virtua Racing"],a:0,exp:"Daytona USA es famoso por su energ\u00eda arcade y frases de audio memorables.",extra:"Fue un gran \u00e9xito en salones arcade, con cabinas enlazadas para carreras multijugador."},
  {t:"m",q:"\u00bfQu\u00e9 juego arcade de Atari de 1976 inspir\u00f3 muchos juegos de romper bloques?",o:["Breakout", "Pong", "Warlords", "Avalanche"],a:0,exp:"Breakout consist\u00eda en destruir ladrillos con una pelota y una paleta.",extra:"Steve Jobs y Steve Wozniak trabajaron en una versi\u00f3n temprana de Breakout para Atari, dato famoso del cruce entre videojuegos y Silicon Valley."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Taito de 1986 elev\u00f3 el plataformas cooperativo de pantalla \u00fanica?",o:["Bubble Bobble", "Snow Bros.", "Bonanza Bros.", "Rod Land"],a:0,exp:"Bubble Bobble fue un cl\u00e1sico cooperativo de pantalla \u00fanica.",extra:"Sus secretos y finales m\u00faltiples incentivaban rejugar y descubrir condiciones ocultas."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Capcom de 1989 puso a pilotos combatiendo en vertical contra ej\u00e9rcitos?",o:["1942", "Commando", "Varth", "Mercs"],a:0,exp:"1942 es un shooter vertical de Capcom ambientado en combate a\u00e9reo.",extra:"Fue uno de los shmups m\u00e1s conocidos de Capcom y tuvo m\u00faltiples secuelas."},
  {t:"m",q:"\u00bfQu\u00e9 shooter de Konami tiene la nave Vic Viper?",o:["Gradius", "R-Type", "Darius", "Xevious"],a:0,exp:"Gradius protagoniza la nave Vic Viper y su sistema de power-ups por barra.",extra:"El jugador eleg\u00eda cu\u00e1ndo activar velocidad, misiles, l\u00e1ser, opciones o escudo, una mec\u00e1nica muy distintiva."},
  {t:"m",q:"\u00bfQu\u00e9 shooter de Irem es famoso por la nave R-9 y el Force pod?",o:["R-Type", "Gradius", "Thunder Force", "Salamander"],a:0,exp:"R-Type usa el Force, un m\u00f3dulo que se acopla y dispara para ataque y defensa.",extra:"Su dificultad y dise\u00f1o de memorizar patrones lo convirtieron en un cl\u00e1sico exigente del g\u00e9nero."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Namco de 1982 fue uno de los primeros shooters verticales con scroll?",o:["Xevious", "Galaga", "Galaxian", "Bosconian"],a:0,exp:"Xevious fue importante por su scroll vertical y objetivos a\u00e9reos y terrestres.",extra:"Inclu\u00eda secretos y una presentaci\u00f3n m\u00e1s sofisticada que muchos shooters anteriores."},
  {t:"m",q:"\u00bfQu\u00e9 arcade de Namco de 1981 es secuela espiritual de Galaxian?",o:["Galaga", "Xevious", "Bosconian", "Mappy"],a:0,exp:"Galaga refin\u00f3 la f\u00f3rmula de disparar contra formaciones alien\u00edgenas.",extra:"Su mec\u00e1nica de nave capturada permit\u00eda recuperar una segunda nave y duplicar disparos, con riesgo y recompensa."},
  {t:"m",q:"\u00bfQu\u00e9 arcade de 1979 de Namco antecedi\u00f3 a Galaga?",o:["Galaxian", "Xevious", "Mappy", "Pole Position"],a:0,exp:"Galaxian fue el precursor directo de Galaga.",extra:"Fue notable por enemigos que romp\u00edan formaci\u00f3n y atacaban en picado con m\u00e1s dinamismo que Space Invaders."},
  {t:"m",q:"\u00bfQu\u00e9 juego de carreras de Namco de 1982 fue influyente en arcades?",o:["Pole Position", "OutRun", "Hang-On", "Final Lap"],a:0,exp:"Pole Position fue un arcade de carreras muy influyente por su perspectiva y clasificaci\u00f3n.",extra:"Ayud\u00f3 a establecer convenciones de juegos de carreras modernos, como vueltas cronometradas y trazado de circuito."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Sega de motos usaba una cabina inclinable?",o:["Hang-On", "OutRun", "Enduro Racer", "Super Hang-On"],a:0,exp:"Hang-On usaba una cabina tipo moto que el jugador inclinaba para controlar.",extra:"Yu Suzuki y Sega ayudaron a convertir los arcades en experiencias f\u00edsicas, no solo pantallas con botones."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Nintendo de 1984 permit\u00eda dise\u00f1ar pistas de motocross?",o:["Excitebike", "Mach Rider", "F-1 Race", "Urban Champion"],a:0,exp:"Excitebike inclu\u00eda carreras de motocross y creaci\u00f3n de pistas.",extra:"La gesti\u00f3n de temperatura del motor y los saltos le daban m\u00e1s profundidad de lo que parec\u00eda."},
  {t:"m",q:"\u00bfQu\u00e9 juego deportivo de arcade exagerado dec\u00eda \u201cHe\u2019s on fire!\u201d?",o:["NBA Jam", "Arch Rivals", "Tecmo Bowl", "Blades of Steel"],a:0,exp:"NBA Jam es famoso por frases como \u201cHe\u2019s on fire!\u201d y jugadas imposibles.",extra:"Su estilo 2 contra 2, clavadas absurdas y voces explosivas lo hicieron un fen\u00f3meno arcade y dom\u00e9stico."},
  {t:"m",q:"\u00bfEn qu\u00e9 a\u00f1o fue lanzado Pac-Man en arcades?",o:["1980","1978","1982","1975"],a:0,exp:"Pac-Man fue lanzado por Namco en 1980 y exportado a Occidente ese mismo a\u00f1o.",extra:"Se convirti\u00f3 en el arcade m\u00e1s vendido de la historia y en s\u00edmbolo cultural de los videojuegos."},
  {t:"m",q:"\u00bfQu\u00e9 sistema de Nintendo de 1989 populariz\u00f3 los juegos port\u00e1tiles con su pantalla monocroma?",o:["Game Boy","Game & Watch","Atari Lynx","Sega Game Gear"],a:0,exp:"Game Boy de Nintendo domin\u00f3 el mercado port\u00e1til gracias a su durabilidad, bater\u00eda y librer\u00eda de juegos.",extra:"Tetris fue incluido como juego de lanzamiento en Occidente, contribuyendo enormemente a su \u00e9xito."},
  {t:"m",q:"\u00bfQu\u00e9 juego de 1993 de id Software revolucion\u00f3 los shooters en primera persona?",o:["Doom","Wolfenstein 3D","Quake","Duke Nukem 3D"],a:0,exp:"Doom populariz\u00f3 el g\u00e9nero FPS y la cultura del shareware, siendo un fen\u00f3meno cultural masivo.",extra:"Su motor permit\u00eda mapas no lineales y fue fundamental para el desarrollo del modding en videojuegos."},
  {t:"m",q:"\u00bfQu\u00e9 consola de Sega rivaliz\u00f3 con la NES en los 80 con el lema 'Genesis Does'?",o:["Sega Genesis / Mega Drive","Sega Master System","Sega Saturn","Sega 32X"],a:0,exp:"La Sega Mega Drive (Genesis en EE.UU.) fue la gran rival de la Super NES en la llamada guerra de las consolas.",extra:"La campa\u00f1a 'Genesis Does What Nintendon't' fue una de las m\u00e1s agresivas de la historia del marketing de videojuegos."},
  {t:"m",q:"\u00bfQu\u00e9 juego de plataformas de Sega protagonizado por un erizo azul debut\u00f3 en 1991?",o:["Sonic the Hedgehog","Alex Kidd in Miracle World","Ristar","Rocket Knight Adventures"],a:0,exp:"Sonic the Hedgehog fue creado como mascota de Sega para competir con Mario, debutando en 1991.",extra:"Su mec\u00e1nica de velocidad extrema y loops fue innovadora para los plataformas de la \u00e9poca."},
  {t:"m",q:"\u00bfQu\u00e9 juego de beat 'em up de Konami de 1989 adaptaba las Tortugas Ninja al arcade?",o:["Teenage Mutant Ninja Turtles","X-Men","The Simpsons","Sunset Riders"],a:0,exp:"Teenage Mutant Ninja Turtles de Konami (1989) permit\u00eda a 4 jugadores simult\u00e1neos en cabinas especiales de arcade.",extra:"La versi\u00f3n dom\u00e9stica en NES fue uno de los juegos m\u00e1s vendidos de la consola, aunque diferente al arcade."},
  {t:"m",q:"\u00bfQu\u00e9 compa\u00f1\u00eda desarroll\u00f3 el m\u00edtico juego de rol Baldur's Gate en 1998?",o:["BioWare","Black Isle Studios","Interplay","Obsidian"],a:0,exp:"Baldur's Gate fue desarrollado por BioWare y publicado por Interplay, siendo uno de los CRPGs m\u00e1s influyentes de la historia.",extra:"Utilizaba el motor Infinity y las reglas de AD&D 2\u00aa edici\u00f3n, revitalizando el inter\u00e9s por los juegos de rol occidentales."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Nintendo de 1986 fue el primer t\u00edtulo de la saga The Legend of Zelda?",o:["The Legend of Zelda","Zelda II: The Adventure of Link","A Link to the Past","Link's Awakening"],a:0,exp:"The Legend of Zelda (1986) en Famicom Disk System present\u00f3 a Link, Zelda y Hyrule por primera vez.",extra:"Fue innovador al incluir una bater\u00eda interna para guardar partidas, una tecnolog\u00eda nueva en la \u00e9poca."},
  {t:"m",q:"\u00bfCu\u00e1l fue la primera consola de Sony que compiti\u00f3 directamente contra el Nintendo 64?",o:["PlayStation","PlayStation 2","Saturn","3DO"],a:0,exp:"PlayStation (1994) fue la primera consola de Sony, compitiendo con Nintendo 64 y Sega Saturn en la quinta generaci\u00f3n.",extra:"La PlayStation populariz\u00f3 el uso de CDs como soporte para videojuegos y atrajo a muchos desarrolladores con sus herramientas accesibles."},
  {t:"m",q:"\u00bfQu\u00e9 juego de estrategia de Blizzard de 1994 populariz\u00f3 el g\u00e9nero RTS con recursos y bases?",o:["Warcraft: Orcs & Humans","StarCraft","Command & Conquer","Dune II"],a:0,exp:"Warcraft: Orcs & Humans (1994) fue el primer juego de Blizzard en popularizar el RTS moderno con facciones asim\u00e9tricas.",extra:"Su \u00e9xito llev\u00f3 directamente a Warcraft II y eventualmente al MMORPG World of Warcraft."},
  {t:"m",q:"\u00bfQu\u00e9 juego de NES de 1985 fue el primer t\u00edtulo de la saga Super Mario Bros. para consola dom\u00e9stica?",o:["Super Mario Bros.","Donkey Kong","Mario Bros.","Duck Hunt"],a:0,exp:"Super Mario Bros. (1985) fue lanzado para NES y defini\u00f3 el est\u00e1ndar de los juegos de plataformas modernos.",extra:"Se vendi\u00f3 junto con la NES como pack-in en EE.UU. y fue el juego m\u00e1s vendido de todos los tiempos durante d\u00e9cadas."},
  {t:"m",q:"\u00bfQu\u00e9 consola de Atari de 1977 populariz\u00f3 los cartuchos intercambiables para consolas dom\u00e9sticas?",o:["Atari 2600","Atari 5200","Atari 7800","Pong Home"],a:0,exp:"El Atari 2600 populariz\u00f3 el concepto de consola con cartuchos intercambiables, permitiendo una librer\u00eda de juegos expandible.",extra:"Space Invaders en Atari 2600 fue tan popular que cuadruplic\u00f3 las ventas de la consola y defini\u00f3 el concepto de killer app."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Midway de 1992 fue pol\u00e9mico por su violencia expl\u00edcita y llev\u00f3 a la creaci\u00f3n del ESRB?",o:["Mortal Kombat","Street Fighter II","Killer Instinct","Primal Rage"],a:0,exp:"Mortal Kombat fue tan pol\u00e9mico por sus fatalities que las audiencias del Congreso de EE.UU. llevaron a la creaci\u00f3n del sistema de clasificaci\u00f3n ESRB.",extra:"La versi\u00f3n de SNES ten\u00eda la sangre reemplazada por sudor por presiones de Nintendo, mientras que la de Sega manten\u00eda la sangre con un c\u00f3digo."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Rare de 1994 revitaliz\u00f3 el plataformas en SNES usando gr\u00e1ficos pre-renderizados 3D?",o:["Donkey Kong Country","Super Mario World 2","Yoshi's Island","Kirby Super Star"],a:0,exp:"Donkey Kong Country (1994) impresion\u00f3 con sus gr\u00e1ficos pre-renderizados 3D y su banda sonora de David Wise.",extra:"Rare us\u00f3 workstations de Silicon Graphics para crear los modelos 3D que luego convert\u00edan a sprites 2D, una t\u00e9cnica novedosa."},
  {t:"m",q:"\u00bfQu\u00e9 juego de PC de LucasArts de 1990 fue pionero en las aventuras gr\u00e1ficas con interfaz de verbos?",o:["The Secret of Monkey Island","Maniac Mansion","Zak McKracken","Indiana Jones and the Last Crusade"],a:0,exp:"The Secret of Monkey Island us\u00f3 el motor SCUMM con interfaz de verbos y fue un hito del humor y la narrativa en videojuegos.",extra:"Guybrush Threepwood y sus aventuras se convirtieron en una saga cl\u00e1sica de las aventuras gr\u00e1ficas de los 90."},
  {t:"m",q:"\u00bfQu\u00e9 sistema de Sega de 1998 fue el primero en incluir un m\u00f3dem integrado para juego online?",o:["Sega Dreamcast","Sega Saturn","PlayStation 2","Nintendo 64"],a:0,exp:"El Sega Dreamcast (1998) fue la primera consola dom\u00e9stica en incluir un m\u00f3dem integrado para conexiones a internet y juego online.",extra:"Phantasy Star Online fue uno de los primeros juegos online exitosos en consola, gracias al Dreamcast."},
  {t:"m",q:"\u00bfQu\u00e9 juego de RPG de Square de 1997 para PlayStation es considerado uno de los mejores de la historia?",o:["Final Fantasy VII","Chrono Trigger","Final Fantasy VI","Xenogears"],a:0,exp:"Final Fantasy VII (1997) revolucion\u00f3 los JRPG con sus gr\u00e1ficos 3D, cinem\u00e1ticas y narrativa madura.",extra:"La muerte de Aerith en el segundo disco es uno de los momentos m\u00e1s impactantes y memorables de la historia de los videojuegos."},
  {t:"m",q:"\u00bfQu\u00e9 juego de beat 'em up de Capcom de 1989 puso a los jugadores en las calles de Metro City?",o:["Final Fight","Streets of Rage","Double Dragon","Cadillacs and Dinosaurs"],a:0,exp:"Final Fight (1989) de Capcom permit\u00eda elegir entre tres personajes para limpiar Metro City de la banda Mad Gear.",extra:"El alcalde Mike Haggar se convirti\u00f3 en personaje ic\u00f3nico, apareciendo en m\u00faltiples juegos de Capcom posteriormente."},
  {t:"m",q:"\u00bfQu\u00e9 simulador de vuelo de Microsoft, lanzado en 1982, se convirti\u00f3 en uno de los programas m\u00e1s longevos de la historia?",o:["Microsoft Flight Simulator","F-19 Stealth Fighter","Chuck Yeager's Air Combat","Falcon"],a:0,exp:"Microsoft Flight Simulator se public\u00f3 originalmente en 1982 y continu\u00f3 con nuevas versiones hasta la actualidad.",extra:"Bill Gates us\u00f3 Flight Simulator internamente en Microsoft como prueba de compatibilidad de hardware para PC."},
  {t:"m",q:"\u00bfQu\u00e9 juego de aventura de texto de Infocom de 1977 fue pionero en las aventuras de texto con el misterioso Grue?",o:["Zork","Adventure (Colossal Cave)","Hitchhiker's Guide to the Galaxy","Enchanter"],a:0,exp:"Zork (1977-1979) fue uno de los juegos de aventura de texto m\u00e1s famosos, con sus cavernas subterr\u00e1neas y la criatura Grue que ataca en la oscuridad.",extra:"Grue se convirti\u00f3 en referencia cultural usada como broma en muchos videojuegos posteriores."},
  {t:"m",q:"\u00bfQu\u00e9 sistema de videojuegos de Nintendo de 1996 introdujo la arquitectura de 64 bits y el joystick anal\u00f3gico moderno?",o:["Nintendo 64","Super NES","Nintendo GameCube","Virtual Boy"],a:0,exp:"Nintendo 64 (1996) introdujo el control anal\u00f3gico en 3D y juegos como Super Mario 64 que definieron el dise\u00f1o de los juegos 3D.",extra:"El controlador de N64 fue controversial por su dise\u00f1o de tres patas pero su stick anal\u00f3gico influy\u00f3 en todos los gamepads modernos."},
  {t:"m",q:"\u00bfQu\u00e9 juego de SNK de 1990 populariz\u00f3 los versus fighters en cabinas con Fatal Fury como primer gran hit?",o:["Fatal Fury","Art of Fighting","Samurai Shodown","King of Fighters"],a:0,exp:"Fatal Fury fue el primer juego de lucha de SNK para Neo Geo y sent\u00f3 las bases del g\u00e9nero en esa plataforma.",extra:"Inclu\u00eda el sistema de dos planos de pelea y personajes ic\u00f3nicos como Terry Bogard."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Capcom de 1994 para Super NES introdujo los movimientos Super Combo?",o:["Super Street Fighter II Turbo","Street Fighter Alpha","Street Fighter III","Hyper Street Fighter II"],a:0,exp:"Super Street Fighter II Turbo introdujo los movimientos Super Combo, precursores de los Super Arts en entregas posteriores.",extra:"La saga Street Fighter II tuvo m\u00faltiples revisiones en arcade antes de llegar a consolas, siendo cada actualizaci\u00f3n un evento."},
  {t:"m",q:"\u00bfQu\u00e9 juego de plataformas de Sega de 1985 fue el primer t\u00edtulo de la saga Alex Kidd?",o:["Alex Kidd in Miracle World","Alex Kidd: The Lost Stars","Wonderboy","Dynamite Dux"],a:0,exp:"Alex Kidd in Miracle World (1986 en Master System) fue la mascota de Sega antes de Sonic.",extra:"Alex Kidd vino integrado en la memoria de la Sega Master System II, siendo el juego que arrancaba al encender la consola."},
  {t:"m",q:"\u00bfEn qu\u00e9 consola de Nintendo debut\u00f3 Metroid protagonizado por Samus Aran en 1986?",o:["Famicom / NES","Super NES","Game Boy","Nintendo 64"],a:0,exp:"Metroid debut\u00f3 en el Famicom Disk System en 1986, siendo uno de los primeros juegos de exploraci\u00f3n no lineal de Nintendo.",extra:"La revelaci\u00f3n de que Samus Aran era una mujer al completar el juego fue un giro sorprendente que marc\u00f3 al g\u00e9nero."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Namco de 1984 fue un pionero en los juegos de carreras con perspectiva trasera?",o:["Pole Position II","Galaga","Dig Dug","Mappy"],a:0,exp:"Pole Position II fue una secuela del cl\u00e1sico de carreras de Namco con perspectiva trasera, influyente en el g\u00e9nero.",extra:"Namco fue uno de los pioneros en los juegos de carreras arcade con perspectiva en tercera persona."},
  {t:"f",q:"Pong fue el primer videojuego de la historia seg\u00fan la mayor\u00eda de historiadores del sector.",o:["Verdadero","Falso"],a:1,exp:"Pong (1972) fue el primer videojuego comercialmente exitoso de Atari, pero no el primero de la historia. Tennis for Two (1958) y Spacewar! (1962) lo precedieron.",extra:"Pong s\u00ed fue el primer videojuego en lograr un \u00e9xito comercial masivo en arcades, lo que lo hace hist\u00f3ricamente clave."},
  {t:"f",q:"La consola Virtual Boy de Nintendo fue un gran \u00e9xito de ventas que redefini\u00f3 la realidad virtual en los videojuegos en 1995.",o:["Verdadero","Falso"],a:1,exp:"Virtual Boy fue un fracaso comercial notable: sus gr\u00e1ficos en rojo monocrom\u00e1tico causaban dolores de cabeza y Nintendo discontinu\u00f3 la consola en menos de un a\u00f1o.",extra:"A pesar de su fracaso, Virtual Boy tiene hoy un culto de coleccionistas y es considerado un artefacto interesante de la historia de Nintendo."},
  {t:"f",q:"El famoso Crash de los videojuegos de 1983 afect\u00f3 principalmente al mercado japon\u00e9s de videojuegos.",o:["Verdadero","Falso"],a:1,exp:"El Crash de 1983 afect\u00f3 principalmente al mercado norteamericano. El mercado japon\u00e9s sigui\u00f3 creciendo con Famicom.",extra:"La saturaci\u00f3n de juegos de baja calidad y el infame port de E.T. para Atari 2600 contribuyeron al colapso. Nintendo revitaliz\u00f3 el mercado occidental con NES en 1985."},
  {t:"f",q:"Street Fighter II fue el primer juego de lucha versus uno a uno con personajes seleccionables.",o:["Verdadero","Falso"],a:1,exp:"Karate Champ (1984) y el Street Fighter original (1987) preceden a Street Fighter II. Sin embargo, SFII populariz\u00f3 masivamente el formato moderno de versus fighters.",extra:"Street Fighter II (1991) s\u00ed estableci\u00f3 los est\u00e1ndares del g\u00e9nero que todos los competidores siguieron, aunque no fue t\u00e9cnicamente el primero."},
  {t:"m",q:"\u00bfQu\u00e9 juego de plataformas de Nintendo de 1990 introdujo a Yoshi, el dinosaurio que puede comerse enemigos?",o:["Super Mario World","Super Mario Bros. 3","Yoshi's Island","Donkey Kong Country"],a:0,exp:"Super Mario World (1990) para Super NES introdujo a Yoshi como montura de Mario, pudiendo comer enemigos y usar habilidades especiales seg\u00fan el color.",extra:"Yoshi se convirti\u00f3 en uno de los personajes m\u00e1s queridos del universo Nintendo y protagoniz\u00f3 su propia saga de juegos."},
  {t:"m",q:"\u00bfQu\u00e9 saga de RPGs japoneses de Enix, creada en 1986, es una de las m\u00e1s longevas del g\u00e9nero?",o:["Dragon Quest","Final Fantasy","Star Ocean","Phantasy Star"],a:0,exp:"Dragon Quest (1986), creada por Yuji Horii, es una de las sagas de RPG japon\u00e9s m\u00e1s antiguas y populares, especialmente en Jap\u00f3n donde es un fen\u00f3meno cultural.",extra:"En Jap\u00f3n, los lanzamientos de Dragon Quest eran eventos nacionales: se vend\u00edan despu\u00e9s del horario escolar para evitar que los estudiantes faltaran a clases para comprarlos."},
  {t:"f",q:"El juego E.T. the Extra-Terrestrial de Atari 2600, lanzado en 1982, fue uno de los mejores juegos de ese a\u00f1o.",o:["Verdadero","Falso"],a:1,exp:"E.T. de Atari 2600 es considerado uno de los peores videojuegos de la historia. Fue desarrollado en solo cinco semanas y contribuy\u00f3 al Crash de 1983.",extra:"Millones de cartuchos sin vender fueron enterrados en un vertedero de Nuevo M\u00e9xico, sitio descubierto y excavado en 2014 como parte de un documental."},
  {t:"m",q:"\u00bfQu\u00e9 juego de Capcom de 1987 para NES fue uno de los primeros grandes \u00e9xitos de la plataforma con su dificultad extrema?",o:["Mega Man","Bionic Commando","Ghosts 'n Goblins","1943"],a:0,exp:"Mega Man (1987) para NES fue el primero de una saga enormemente popular, conocido por su dificultad y la mec\u00e1nica de absorber los poderes de los jefes derrotados.",extra:"Aunque el primer Mega Man tuvo ventas modestas, su sequel Mega Man 2 (1988) fue un \u00e9xito masivo que lanz\u00f3 una de las franquicias m\u00e1s prol\u00edficas de Capcom."}
];

export default retrogamingQuestions;
